import React, { useEffect, useMemo, useRef, useState } from 'react';
import TodoInput from './components/TodoInput.jsx';
import TodoList from './components/TodoList.jsx';
import TodoStats from './components/TodoStats.jsx';
import { FILTERS, PRIORITY_ORDER, UNDO_TIMEOUT_MS, STORAGE_KEYS, THEMES } from './constants.js';
import { normalizePriority } from './utils/todoHelpers.js';
import { getDueDateSortValue } from './utils/dateHelpers.js';

function App() {
  const [todos, setTodos] = useState(() => {
    try {
      const stored = window.localStorage.getItem(STORAGE_KEYS.TODOS);
      const parsed = stored ? JSON.parse(stored) : [];
      if (!Array.isArray(parsed)) return [];
      return parsed.map((todo) => ({
        ...todo,
        priority: normalizePriority(todo.priority),
      }));
    } catch {
      return [];
    }
  });
  const [filter, setFilter] = useState('all'); // 'all' | 'active' | 'completed'
  const [searchQuery, setSearchQuery] = useState('');
  const [theme, setTheme] = useState(() => {
    if (typeof window === 'undefined') return THEMES.LIGHT;
    const stored = window.localStorage.getItem(STORAGE_KEYS.THEME);
    if (stored === THEMES.DARK || stored === THEMES.LIGHT) return stored;
    // Fallback to system preference
    if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
      return THEMES.DARK;
    }
    return THEMES.LIGHT;
  });
  const [showStats, setShowStats] = useState(() => {
    if (typeof window === 'undefined') return false;
    const stored = window.localStorage.getItem(STORAGE_KEYS.SHOW_STATS);
    return stored === 'true';
  });

  // Undo state for destructive actions (delete / clear completed)
  const [undoState, setUndoState] = useState(null);
  // { message: string, prevTodos: Todo[], createdAt: number }
  const undoTimerRef = useRef(null);

  useEffect(() => {
    try {
      window.localStorage.setItem(STORAGE_KEYS.TODOS, JSON.stringify(todos));
    } catch {
      // Best-effort persistence; ignore errors (e.g., private mode or quota issues)
    }
  }, [todos]);

  useEffect(() => {
    try {
      window.localStorage.setItem(STORAGE_KEYS.THEME, theme);
    } catch {
      // ignore
    }
    if (typeof document !== 'undefined') {
      document.documentElement.dataset.theme = theme;
    }
  }, [theme]);

  useEffect(() => {
    try {
      window.localStorage.setItem(STORAGE_KEYS.SHOW_STATS, showStats.toString());
    } catch {
      // ignore
    }
  }, [showStats]);

  useEffect(() => {
    // Clear any existing timer when undoState changes
    if (undoTimerRef.current) {
      window.clearTimeout(undoTimerRef.current);
      undoTimerRef.current = null;
    }

    if (!undoState) return;

    undoTimerRef.current = window.setTimeout(() => {
      setUndoState(null);
    }, UNDO_TIMEOUT_MS);

    return () => {
      if (undoTimerRef.current) {
        window.clearTimeout(undoTimerRef.current);
        undoTimerRef.current = null;
      }
    };
  }, [undoState]);

  const showUndo = (message, prevTodos) => {
    setUndoState({ message, prevTodos, createdAt: Date.now() });
  };

  const handleUndo = () => {
    if (!undoState) return;
    setTodos(undoState.prevTodos);
    setUndoState(null);
  };

  const handleDismissUndo = () => {
    setUndoState(null);
  };

  const generateTodoId = () => {
    // Prefer collision-resistant IDs when available.
    // Fallback keeps behavior stable in older environments.
    if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
      return crypto.randomUUID();
    }
    return `${Date.now()}-${Math.random().toString(16).slice(2)}`;
  };

  const handleAddTodo = (text, priority, dueDate) => {
    const trimmed = text.trim();
    if (!trimmed) return;

    const newTodo = {
      id: generateTodoId(),
      text: trimmed,
      completed: false,
      priority: normalizePriority(priority),
      dueDate: dueDate || null,
    };

    setTodos((prev) => [newTodo, ...prev]);
  };

  const handleToggleTodo = (id) => {
    setTodos((prev) =>
      prev.map((todo) =>
        todo.id === id ? { ...todo, completed: !todo.completed } : todo
      )
    );
  };

  const handleDeleteTodo = (id) => {
    setTodos((prev) => {
      const next = prev.filter((todo) => todo.id !== id);
      if (next.length !== prev.length) {
        showUndo('Todo deleted.', prev);
      }
      return next;
    });
  };

  const handleClearCompleted = () => {
    setTodos((prev) => {
      const next = prev.filter((todo) => !todo.completed);
      if (next.length !== prev.length) {
        showUndo('Completed todos cleared.', prev);
      }
      return next;
    });
  };

  const handleChangeTodoPriority = (id, priority) => {
    const normalized = normalizePriority(priority);
    setTodos((prev) =>
      prev.map((todo) =>
        todo.id === id ? { ...todo, priority: normalized } : todo
      )
    );
  };

  const handleEditTodo = (id, nextText, nextDueDate) => {
    const trimmed = (nextText ?? '').trim();
    if (!trimmed) return;

    setTodos((prev) =>
      prev.map((todo) =>
        todo.id === id
          ? {
              ...todo,
              text: trimmed,
              dueDate: nextDueDate || null,
            }
          : todo
      )
    );
  };

  const normalizedSearch = searchQuery.trim().toLowerCase();

  const filteredTodos = useMemo(() => {
    return todos
      .filter((todo) => {
        if (filter === 'active') return !todo.completed;
        if (filter === 'completed') return todo.completed;
        return true; // 'all'
      })
      .filter((todo) => {
        if (!normalizedSearch) return true;
        const text = (todo.text || '').toLowerCase();
        return text.includes(normalizedSearch);
      })
      .map((todo, index) => ({ todo, index }))
      .sort((a, b) => {
        // First sort by due date status
        const aDueDatePriority = getDueDateSortValue(a.todo.dueDate);
        const bDueDatePriority = getDueDateSortValue(b.todo.dueDate);

        if (aDueDatePriority !== bDueDatePriority) {
          return aDueDatePriority - bDueDatePriority;
        }

        // Then by priority level
        const aPriority = PRIORITY_ORDER[normalizePriority(a.todo.priority)];
        const bPriority = PRIORITY_ORDER[normalizePriority(b.todo.priority)];
        if (aPriority !== bPriority) {
          return bPriority - aPriority; // high > medium > low
        }

        // Finally preserve original order for equal priority and due date
        return a.index - b.index;
      })
      .map((entry) => entry.todo);
  }, [todos, filter, normalizedSearch]);

  const itemsLeft = useMemo(() => todos.filter((todo) => !todo.completed).length, [todos]);
  const hasCompleted = useMemo(() => todos.some((todo) => todo.completed), [todos]);

  const toggleTheme = () => {
    setTheme((prev) => (prev === THEMES.DARK ? THEMES.LIGHT : THEMES.DARK));
  };

  const toggleStats = () => {
    setShowStats((prev) => !prev);
  };

  return (
    <main className="app-main">
      <div className="app-container">
        <header className="app-header">
          <h1 className="app-title">Todo App</h1>
          <div className="header-buttons">
            <button
              type="button"
              className="stats-toggle-button"
              onClick={toggleStats}
              aria-label={showStats ? 'Hide statistics' : 'Show statistics'}
              aria-pressed={showStats}
            >
              📊 Stats
            </button>
            <button
              type="button"
              className="theme-toggle-button"
              onClick={toggleTheme}
              aria-label={theme === THEMES.DARK ? 'Switch to light theme' : 'Switch to dark theme'}
            >
              {theme === THEMES.DARK ? '☀️ Light' : '🌙 Dark'}
            </button>
          </div>
        </header>

        {showStats && <TodoStats todos={todos} />}

        <TodoInput onAddTodo={handleAddTodo} />

        <div className="filters">
          {FILTERS.map((option) => (
            <button
              key={option.id}
              type="button"
              className={
                filter === option.id ? 'filter-button active' : 'filter-button'
              }
              aria-pressed={filter === option.id}
              onClick={() => setFilter(option.id)}
            >
              {option.label}
            </button>
          ))}
        </div>

        <div className="search-bar">
          <label className="visually-hidden" htmlFor="todo-search-input">
            Search todos
          </label>
          <input
            id="todo-search-input"
            type="search"
            className="search-input"
            placeholder="Search by text..."
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
        </div>

        <p className="items-left" aria-live="polite">
          {itemsLeft} item{itemsLeft !== 1 ? 's' : ''} left
        </p>

        <button
          type="button"
          className="clear-completed-button"
          onClick={handleClearCompleted}
          disabled={!hasCompleted}
        >
          Clear completed
        </button>

        <TodoList
          todos={filteredTodos}
          onToggleTodo={handleToggleTodo}
          onDeleteTodo={handleDeleteTodo}
          onChangeTodoPriority={handleChangeTodoPriority}
          onEditTodo={handleEditTodo}
        />

        {undoState && (
          <div className="undo-toast" role="status" aria-live="polite">
            <span className="undo-message">{undoState.message}</span>
            <div className="undo-actions">
              <button type="button" className="undo-button" onClick={handleUndo}>
                Undo
              </button>
              <button
                type="button"
                className="undo-dismiss"
                onClick={handleDismissUndo}
                aria-label="Dismiss"
              >
        ...[truncated]

/**
 * Application-wide constants
 */

// Filter options for todo list
export const FILTERS = [
  { id: 'all', label: 'All' },
  { id: 'active', label: 'Active' },
  { id: 'completed', label: 'Completed' },
];

// Priority levels and their sort order
export const PRIORITY_ORDER = {
  low: 1,
  medium: 2,
  high: 3,
};

export const VALID_PRIORITIES = ['low', 'medium', 'high'];
export const DEFAULT_PRIORITY = 'medium';

// Undo timeout in milliseconds
export const UNDO_TIMEOUT_MS = 6000;

// LocalStorage keys
export const STORAGE_KEYS = {
  TODOS: 'todos',
  THEME: 'theme',
  SHOW_STATS: 'showStats',
};

// Theme options
export const THEMES = {
  LIGHT: 'light',
  DARK: 'dark',
};

import React, { useEffect, useRef, useState } from 'react';
import { getTodayString, isOverdue } from '../utils/dateHelpers.js';

// TodoInput manages only local input state and delegates todo creation
// to its parent via the onAddTodo callback.
function TodoInput({ onAddTodo }) {
  const [text, setText] = useState('');
  const [priority, setPriority] = useState('medium');
  const [dueDate, setDueDate] = useState('');
  const inputRef = useRef(null);
  const isEmpty = text.trim().length === 0; // controls disabled state of the Add button

  useEffect(() => {
    if (inputRef.current) {
      inputRef.current.focus();
    }
  }, []);

  const submitCurrentText = () => {
    const trimmed = text.trim();
    if (!trimmed) return;

    // Allow submitting an existing overdue date (e.g., from manual edit),
    // but prevent creating a *new* todo with an overdue dueDate.
    const normalizedDueDate = dueDate || null;
    const safeDueDate = normalizedDueDate && isOverdue(normalizedDueDate) ? null : normalizedDueDate;

    if (typeof onAddTodo === 'function') {
      onAddTodo(trimmed, priority, safeDueDate);
    }
    setText('');
    setPriority('medium');
    setDueDate('');
    if (inputRef.current) {
      inputRef.current.focus();
    }
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    submitCurrentText();
  };

  const handleKeyDown = (event) => {
    if (event.key === 'Escape') {
      event.preventDefault();
      setText('');
      return;
    }

    if ((event.ctrlKey || event.metaKey) && event.key === 'Enter') {
      event.preventDefault();
      submitCurrentText();
    }
  };

  return (
    <form className="todo-input" onSubmit={handleSubmit}>
      <label className="visually-hidden" htmlFor="new-todo-input">
        Add a new todo
      </label>
      <input
        id="new-todo-input"
        type="text"
        className="todo-input-field"
        placeholder="What needs to be done?"
        value={text}
        onChange={(e) => setText(e.target.value)}
        onKeyDown={handleKeyDown}
        ref={inputRef}
      />
      <label className="visually-hidden" htmlFor="todo-priority-select">
        Todo priority
      </label>
      <select
        id="todo-priority-select"
        className="priority-select"
        value={priority}
        onChange={(e) => setPriority(e.target.value)}
      >
        <option value="low">Low</option>
        <option value="medium">Medium</option>
        <option value="high">High</option>
      </select>
      <label className="visually-hidden" htmlFor="todo-due-date-input">
        Due date (optional)
      </label>
      <input
        id="todo-due-date-input"
        type="date"
        className="due-date-input"
        value={dueDate}
        onChange={(e) => setDueDate(e.target.value)}
        min={getTodayString()}
      />
      <button type="submit" className="add-button" disabled={isEmpty}>
        Add
      </button>
    </form>
  );
}

export default TodoInput;

import React, { useEffect, useRef, useState } from 'react';
import { normalizePriority } from '../utils/todoHelpers.js';
import { formatDueDate, getDueDateStatus, getTodayString, isOverdue } from '../utils/dateHelpers.js';

function TodoItem({ todo, onToggleTodo, onDeleteTodo, onChangeTodoPriority, onEditTodo }) {
  const [isEditing, setIsEditing] = useState(false);
  const [draftText, setDraftText] = useState(todo?.text ?? '');
  const [draftDueDate, setDraftDueDate] = useState(todo?.dueDate ?? '');
  const editInputRef = useRef(null);

  useEffect(() => {
    setDraftText(todo?.text ?? '');
    setDraftDueDate(todo?.dueDate ?? '');
  }, [todo?.text, todo?.dueDate]);

  useEffect(() => {
    if (isEditing && editInputRef.current) {
      editInputRef.current.focus();
      editInputRef.current.select?.();
    }
  }, [isEditing]);

  const handleToggle = () => {
    if (typeof onToggleTodo === 'function') {
      onToggleTodo(todo.id);
    }
  };

  const handleDelete = () => {
    if (typeof onDeleteTodo === 'function') {
      onDeleteTodo(todo.id);
    }
  };

  const effectivePriority = normalizePriority(todo?.priority);

  const handlePriorityChange = (event) => {
    const newPriority = event.target.value;
    if (typeof onChangeTodoPriority === 'function') {
      onChangeTodoPriority(todo.id, newPriority);
    }
  };

  const startEdit = () => {
    setDraftText(todo?.text ?? '');
    setDraftDueDate(todo?.dueDate ?? '');
    setIsEditing(true);
  };

  const cancelEdit = () => {
    setDraftText(todo?.text ?? '');
    setDraftDueDate(todo?.dueDate ?? '');
    setIsEditing(false);
  };

  const saveEdit = () => {
    const trimmed = (draftText ?? '').trim();
    if (!trimmed) return;

    const normalizedDueDate = draftDueDate || null;
    if (normalizedDueDate && isOverdue(normalizedDueDate)) return;

    if (typeof onEditTodo === 'function') {
      onEditTodo(todo.id, trimmed, normalizedDueDate);
    }
    setIsEditing(false);
  };

  const clearDueDate = () => {
    setDraftDueDate('');
  };

  const handleEditKeyDown = (event) => {
    if (event.key === 'Escape') {
      event.preventDefault();
      cancelEdit();
      return;
    }

    if ((event.ctrlKey || event.metaKey) && event.key === 'Enter') {
      event.preventDefault();
      saveEdit();
    }
  };

  const dueDateStatus = getDueDateStatus(todo.dueDate);

  const handleRowKeyDown = (event) => {
    if (isEditing) return;

    if (event.key === 'Enter') {
      event.preventDefault();
      handleToggle();
      return;
    }

    if (event.key === 'Delete' || event.key === 'Backspace') {
      event.preventDefault();
      handleDelete();
      return;
    }

    if (event.key === 'e' || event.key === 'E') {
      event.preventDefault();
      startEdit();
    }
  };

  return (
    <li
      className={`todo-item priority-${effectivePriority} ${
        dueDateStatus ? `due-status-${dueDateStatus}` : ''
      }`}
      tabIndex={0}
      role="group"
      aria-label={todo.text ? `Todo: ${todo.text}` : 'Todo'}
      onKeyDown={handleRowKeyDown}
    >
      <div className="todo-item-content">
        <input
          type="checkbox"
          checked={!!todo.completed}
          onChange={handleToggle}
          aria-label={todo.text ? `Toggle todo: ${todo.text}` : 'Toggle todo'}
        />

        {isEditing ? (
          <div className="todo-edit-fields" onKeyDown={handleEditKeyDown}>
            <input
              ref={editInputRef}
              type="text"
              className="todo-edit-input"
              value={draftText}
              onChange={(e) => setDraftText(e.target.value)}
              aria-label="Edit todo text"
            />
            <div className="todo-edit-date-row">
              <input
                type="date"
                className="todo-edit-date"
                value={draftDueDate || ''}
                onChange={(e) => setDraftDueDate(e.target.value)}
                aria-label="Edit due date"
                min={getTodayString()}
              />
              <button
                type="button"
                className="todo-edit-date-clear"
                onClick={clearDueDate}
                disabled={!draftDueDate}
                aria-label="Clear due date"
              >
                Clear
              </button>
            </div>
            {draftDueDate && isOverdue(draftDueDate) && (
              <p className="todo-edit-date-warning" role="status">
                Due date can’t be in the past.
              </p>
            )}
          </div>
        ) : (
          <>
            <span className={todo.completed ? 'todo-text completed' : 'todo-text'}>
              {todo.text}
            </span>
            {todo.dueDate && (
              <span className={`due-date-badge due-date-${dueDateStatus}`}>
                {dueDateStatus === 'overdue' && '⚠️ '}
                {dueDateStatus === 'due-today' && '📅 '}
                Due {formatDueDate(todo.dueDate)}
              </span>
            )}
            <span className={`priority-badge priority-badge-${effectivePriority}`}>
              {effectivePriority === 'high'
                ? 'High'
                : effectivePriority === 'low'
                  ? 'Low'
                  : 'Medium'}
            </span>
          </>
        )}
      </div>

      <select
        className="priority-select-item"
        aria-label="Change todo priority"
        value={effectivePriority}
        onChange={handlePriorityChange}
        disabled={isEditing}
      >
        <option value="low">Low</option>
        <option value="medium">Medium</option>
        <option value="high">High</option>
      </select>

      {isEditing ? (
        <>
          <button type="button" className="edit-save-button" onClick={saveEdit}>
            Save
          </button>
          <button type="button" className="edit-cancel-button" onClick={cancelEdit}>
            Cancel
          </button>
        </>
      ) : (
        <button type="button" className="edit-button" onClick={startEdit}>
          Edit
        </button>
      )}

      <button
        type="button"
        className="delete-button"
        onClick={handleDelete}
        aria-label={todo.text ? `Delete todo: ${todo.text}` : 'Delete todo'}
        disabled={isEditing}
      >
        Delete
      </button>
    </li>
  );
}

export default TodoItem;

import React from 'react';
import TodoItem from './TodoItem.jsx';

function TodoList({ todos, onToggleTodo, onDeleteTodo, onChangeTodoPriority, onEditTodo }) {
  if (!todos || todos.length === 0) {
    return <p className="empty-state">No todos yet. Add one above!</p>;
  }

  return (
    <ul className="todo-list">
      {todos.map((todo) => (
        <TodoItem
          key={todo.id}
          todo={todo}
          onToggleTodo={onToggleTodo}
          onDeleteTodo={onDeleteTodo}
          onChangeTodoPriority={onChangeTodoPriority}
          onEditTodo={onEditTodo}
        />
      ))}
    </ul>
  );
}

export default TodoList;

import React from 'react';
import { isOverdue, isDueToday } from '../utils/dateHelpers.js';
import { normalizePriority } from '../utils/todoHelpers.js';

function TodoStats({ todos }) {
  // Calculate statistics
  const totalTodos = todos.length;
  const completedTodos = todos.filter((todo) => todo.completed).length;
  const activeTodos = totalTodos - completedTodos;
  const completionRate = totalTodos > 0 ? Math.round((completedTodos / totalTodos) * 100) : 0;

  // Priority breakdown (normalize to be resilient to older/invalid persisted data)
  const highPriority = todos.filter((todo) => normalizePriority(todo.priority) === 'high' && !todo.completed).length;
  const mediumPriority = todos.filter((todo) => normalizePriority(todo.priority) === 'medium' && !todo.completed).length;
  const lowPriority = todos.filter((todo) => normalizePriority(todo.priority) === 'low' && !todo.completed).length;

  // Due date calculations
  const overdueTasks = todos.filter((todo) => !todo.completed && isOverdue(todo.dueDate)).length;
  const tasksDueToday = todos.filter((todo) => !todo.completed && isDueToday(todo.dueDate)).length;


  return (
    <div className="todo-stats">
      <h2 className="stats-title">📊 Statistics</h2>

      <div className="stats-grid">
        {/* Total Todos */}
        <div className="stat-card">
          <div className="stat-icon">📝</div>
          <div className="stat-content">
            <div className="stat-label">Total Todos</div>
            <div className="stat-value">{totalTodos}</div>
          </div>
        </div>

        {/* Active Todos */}
        <div className="stat-card">
          <div className="stat-icon">⚡</div>
          <div className="stat-content">
            <div className="stat-label">Active</div>
            <div className="stat-value">{activeTodos}</div>
          </div>
        </div>

        {/* Completed Todos */}
        <div className="stat-card">
          <div className="stat-icon">✅</div>
          <div className="stat-content">
            <div className="stat-label">Completed</div>
            <div className="stat-value">{completedTodos}</div>
          </div>
        </div>

        {/* Overdue Tasks */}
        <div className="stat-card stat-card-warning">
          <div className="stat-icon">⚠️</div>
          <div className="stat-content">
            <div className="stat-label">Overdue</div>
            <div className="stat-value">{overdueTasks}</div>
          </div>
        </div>

        {/* Tasks Due Today */}
        <div className="stat-card stat-card-info">
          <div className="stat-icon">📅</div>
          <div className="stat-content">
            <div className="stat-label">Due Today</div>
            <div className="stat-value">{tasksDueToday}</div>
          </div>
        </div>
      </div>

      {/* Completion Progress Bar */}
      <div className="progress-section">
        <div className="progress-header">
          <span className="progress-label">Completion Rate</span>
          <span className="progress-percentage">{completionRate}%</span>
        </div>
        <div className="progress-bar-container">
          <div 
            className="progress-bar-fill" 
            style={{ width: `${completionRate}%` }}
            role="progressbar"
            aria-valuenow={completionRate}
            aria-valuemin="0"
            aria-valuemax="100"
            aria-label={`${completionRate}% of todos completed`}
          />
        </div>
      </div>

      {/* Priority Breakdown */}
      <div className="priority-breakdown">
        <h3 className="breakdown-title">Active Tasks by Priority</h3>
        <div className="priority-stats">
          <div className="priority-stat priority-stat-high">
            <span className="priority-stat-icon">🔴</span>
            <span className="priority-stat-label">High</span>
            <span className="priority-stat-value">{highPriority}</span>
          </div>
          <div className="priority-stat priority-stat-medium">
            <span className="priority-stat-icon">🟡</span>
            <span className="priority-stat-label">Medium</span>
            <span className="priority-stat-value">{mediumPriority}</span>
          </div>
          <div className="priority-stat priority-stat-low">
            <span className="priority-stat-icon">🟢</span>
            <span className="priority-stat-label">Low</span>
            <span className="priority-stat-value">{lowPriority}</span>
          </div>
        </div>
      </div>

      {/* Quick Insights */}
      {totalTodos > 0 && (
        <div className="quick-insights">
          {completionRate === 100 && (
            <div className="insight insight-success">
              🎉 Amazing! All tasks completed!
            </div>
          )}
          {overdueTasks > 0 && (
            <div className="insight insight-warning">
              ⏰ You have {overdueTasks} overdue task{overdueTasks !== 1 ? 's' : ''}
            </div>
          )}
          {tasksDueToday > 0 && (
            <div className="insight insight-info">
              📌 {tasksDueToday} task{tasksDueToday !== 1 ? 's' : ''} due today
            </div>
          )}
          {activeTodos === 0 && totalTodos > 0 && (
            <div className="insight insight-success">
              ✨ All caught up! Great work!
            </div>
          )}
        </div>
      )}
    </div>
  );
}

