              className="todo-edit-input"
              value={draftText}
              onChange={(e) => setDraftText(e.target.value)}
              aria-label="Edit todo text"
            />
            <div className="todo-edit-date-row">
              <input
                type="date"
                className="todo-edit-date"
                value={draftDueDate || ''}
